        {cn: "\u5b66\u4e60\u5199\u666f\u4e0e\u8bae\u8bba\u7ed3\u5408\u7684\u624b\u6cd5\uff0c\u7406\u89e3\u201c\u9886\u5b57\u201d\u7684\u4f5c\u7528", en: "Learn the technique of combining scenery with argument; understand the function of \u2018leading characters\u2019 in ci poetry"}
